import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
// import { ToastContainer } from 'react-toastify';
// import { handleError, handleSuccess } from '../utils';
import './Signup.css';

// Importation correcte de l'image
//import signupImage from '../pages/1.png';



const Signup = () => {
    const [signupInfo, setSignupInfo] = useState({
        name: '',
        email: '',
        password: '',
        role: 'client',
        image: null // Fichier image
    });

    const navigate = useNavigate();

    const handleChange = (e) => {
        const { name, value } = e.target;
        setSignupInfo({ ...signupInfo, [name]: value });
    };

    const handleImageChange = (e) => {
        setSignupInfo({ ...signupInfo, image: e.target.files[0] });
    };

    const handleSignup = async (e) => {
        e.preventDefault();

        if (!signupInfo.name || !signupInfo.email || !signupInfo.password) {
            alert("All fields are required");
            return;
        }

        const formData = new FormData();
        formData.append('name', signupInfo.name);
        formData.append('email', signupInfo.email);
        formData.append('password', signupInfo.password);
        formData.append('role', signupInfo.role);
        if (signupInfo.image) {
            formData.append('image', signupInfo.image);
        }

        try {
            const response = await fetch('http://localhost:5001/auth/signup', {
                method: 'POST',
                body: formData
            });

            const result = await response.json();
            if (result.success) {
                alert(result.message);
                navigate('/dashboard');
            } else {
                alert(result.message);
            }
        } catch (err) {
            alert("Error signing up");
        }
    };

    return (
        <form onSubmit={handleSignup}>
            <input type='text' name='name' placeholder='Full Name' onChange={handleChange} value={signupInfo.name} />
            <input type='email' name='email' placeholder='Email Address' onChange={handleChange} value={signupInfo.email} />
            <input type='password' name='password' placeholder='Password' onChange={handleChange} value={signupInfo.password} />
            <input type='file' name='image' onChange={handleImageChange} />

            <button type='submit'>Sign Up</button>
        </form>
    );
};

export default Signup;
